select v_1 as "s_suppkey", v_2 as "s_name", v_3 as "s_address", v_4 as "s_phone", v_5 as "total_revenue" from (select * from (select * from (select "s_suppkey" as v_1, "s_name" as v_2, "s_address" as v_3, "s_nationkey" as v_6, "s_phone" as v_4, "s_acctbal" as v_7, "s_comment" as v_8 from "supplier") l inner join (select v_9 as v_10, sum(v_11 * (1 - v_12)) as v_5 from (select * from (select "l_orderkey" as v_13, "l_partkey" as v_14, "l_suppkey" as v_9, "l_linenumber" as v_15, "l_quantity" as v_16, "l_extendedprice" as v_11, "l_discount" as v_12, "l_tax" as v_17, "l_returnflag" as v_18, "l_linestatus" as v_19, "l_shipdate" as v_20, "l_commitdate" as v_21, "l_receiptdate" as v_22, "l_shipinstruct" as v_23, "l_shipmode" as v_24, "l_comment" as v_25 from "lineitem") s where (v_20 >= (date('1996-01-01', '+0 seconds'))) and (v_20 < (date('1996-01-01', '+3 months')))) s group by 1) r on v_1 = v_10) s where v_5 = ((select v_26 from (select max(v_27) as v_26 from (select v_28 as v_29, sum(v_30 * (1 - v_31)) as v_27 from (select * from (select "l_orderkey" as v_32, "l_partkey" as v_33, "l_suppkey" as v_28, "l_linenumber" as v_34, "l_quantity" as v_35, "l_extendedprice" as v_30, "l_discount" as v_31, "l_tax" as v_36, "l_returnflag" as v_37, "l_linestatus" as v_38, "l_shipdate" as v_39, "l_commitdate" as v_40, "l_receiptdate" as v_41, "l_shipinstruct" as v_42, "l_shipmode" as v_43, "l_comment" as v_44 from "lineitem") s where (v_39 >= (date('1996-01-01', '+0 seconds'))) and (v_39 < (date('1996-01-01', '+3 months')))) s group by 1) s) s))) s order by v_1
